func (o *CCarEntry) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "CCarDrivers":
		rels, ok := retrieved.(CCarDriverSlice)
		if !ok {
			return fmt.Errorf("cCarEntry cannot load %T as %q", retrieved, name)
		}

		o.R.CCarDrivers = rels
		o.R.Loaded.CCarDrivers = true

		for _, rel := range rels {
			if rel != nil {
				rel.R.CCarEntry = o
				rel.R.Loaded.CCarEntry = true
			}
		}
		return nil
	case "CCar":
		rel, ok := retrieved.(*CCar)
		if !ok {
			return fmt.Errorf("cCarEntry cannot load %T as %q", retrieved, name)
		}

		o.R.CCar = rel
		o.R.Loaded.CCar = true

		if rel != nil {
			rel.R.CCarEntries = CCarEntrySlice{o}
		}
		return nil
	case "Event":
		rel, ok := retrieved.(*Event)
		if !ok {
			return fmt.Errorf("cCarEntry cannot load %T as %q", retrieved, name)
		}

		o.R.Event = rel
		o.R.Loaded.Event = true

		if rel != nil {
			rel.R.CCarEntries = CCarEntrySlice{o}
		}
		return nil
	case "CCarTeams":
		rels, ok := retrieved.(CCarTeamSlice)
		if !ok {
			return fmt.Errorf("cCarEntry cannot load %T as %q", retrieved, name)
		}

		o.R.CCarTeams = rels
		o.R.Loaded.CCarTeams = true

		for _, rel := range rels {
			if rel != nil {
				rel.R.CCarEntry = o
				rel.R.Loaded.CCarEntry = true
			}
		}
		return nil
	default:
		return fmt.Errorf("cCarEntry has no relationship %q", name)
	}
}

